import pathlib
import yaml
import json

from python_on_whales import docker

from Deadline.open_studio_landscapes.constants import *
from Deadline.open_studio_landscapes.utils import *

from dagster import (
    AssetIn,
    AssetKey,
    AssetExecutionContext,
    asset,
    Output,
    AssetMaterialization,
    MetadataValue,
)

from Deadline.open_studio_landscapes.assets import KEY as KEY_BASE


GROUP = "Grafana"
KEY = "Grafana"

asset_header = {
    "group_name": GROUP,
    "key_prefix": [KEY],
    "compute_kind": "python"
}


@asset(
    **asset_header,
    ins={
        "env": AssetIn(
            AssetKey([KEY_BASE, "env"]),
        ),
    },
)
def env(
        context: AssetExecutionContext,
        env: dict,
) -> dict:

    # @formatter:off
    _env = {
        "GRAFANA_PORT_HOST": "3030",
        "GRAFANA_PORT_CONTAINER": "3030",
    }
    # @formatter:on

    env.update(_env)

    env_json = pathlib.Path(
        env["DOT_LANDSCAPES"],
        env.get("LANDSCAPE", "default"),
        "third_party",
        *context.asset_key.path,
        f"{'__'.join(context.asset_key.path)}.json",
    )

    env_json.parent.mkdir(parents=True, exist_ok=True)

    with open(env_json, "w") as fw:
        json.dump(
            obj=_env.copy(),
            fp=fw,
            indent=2,
            ensure_ascii=True,
            sort_keys=True,
        )

    yield Output(env)

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            "__".join(context.asset_key.path): MetadataValue.json(env),
            "json": MetadataValue.path(env_json),
        },
    )


